              import sailpoint.object.Application;
              import sailpoint.object.Identity;
              import sailpoint.object.Link;
              import sailpoint.tools.Util;

              boolean flag = false;

              String result ="";
              Identity managerIdentity = identity.getManager();
              if(managerIdentity!=null){
              List links = managerIdentity.getLinks();
              if(!Util.isEmpty(links)){
              for(Link link : links){
              if(link !=null && link.getApplication() !=null){
              if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(),"DB-Peoplesoft-HCM-Primary")){
              result = managerIdentity.getStringAttribute("employeeId");
              break;
              }
              }
              }
              }
              if(Util.isNullOrEmpty(result)){
              result = managerIdentity.getStringAttribute("internalId");
              }
              }

              // get contractormanager internalid for amita non hr contractor 
              if(Util.nullSafeCaseInsensitiveEq("AMITA Health",identity.getStringAttribute("ministry"))){
              if(Util.nullSafeCaseInsensitiveEq("non-hr contractor",identity.getStringAttribute("type"))){
              if(Util.isNotNullOrEmpty(identity.getStringAttribute("contractorManager"))){
              Identity contractorManagerObj = context.getObjectByName(Identity.class,identity.getStringAttribute("contractorManager"));
              if(contractorManagerObj !=null && Util.isNotNullOrEmpty(contractorManagerObj.getStringAttribute("internalId"))){
              result = contractorManagerObj.getStringAttribute("internalId");
              }
              }
              }
              }
              return result;

